require('dotenv').config();
const HDWalletProvider = require('truffle-hdwallet-provider');
const Web3 = require('web3');

const privateKey = process.env.PRIVATE_KEY;
const infuraId = process.env.INFURA_ID;

const provider = new HDWalletProvider(privateKey, `https://mainnet.infura.io/v3/${infuraId}`);
const web3 = new Web3(provider);

// Add network id if needed
web3.currentProvider.network = 1; // mainnet

const accounts = await web3.eth.getAccounts();
console.log('Connected account:', accounts[0]);

async function sendEther(to, value) {
    const txParams = {
        from: accounts[0],
        to,
        value,
        gas: 500000, // adjust as needed
        gasPrice: web3.utils.toWei('10', 'gwei')
    };

    const txHash = await new Promise((resolve, reject) => {
        web3.eth.sendTransaction(txParams, (err, hash) => err ? reject(err) : resolve(hash));
    });
    console.log('Transaction hashed:', txHash);
}

